        g_effect_fetch_compress_objects_data(buf, &len);

    v_result = caml_alloc(len, 0);
    for (int i = 0; i < len; i++)
        Store_field(v_result, i, Val_long(buf[i]));

    CAMLreturn(v_result);
}

