    CAMLparam1(v_packed);
    if (g_effect_execute_compress_objects) {
        int len = Wosize_val(v_packed);
        int32_t* buf = (int32_t*)malloc(len * sizeof(int32_t));
        for (int i = 0; i < len; i++)
            buf[i] = (int32_t)Long_val(Field(v_packed, i));
        g_effect_execute_compress_objects(buf, len);
