        v_gp = Atom(0);
        v_gd = Atom(0);
    }

    value args[27] = {
        Val_long(cc_been_hit), Val_long(cc_player_seen), Val_long(cc_next_fire_time),
        Val_long(n_guns), v_gp, v_gd,
        Val_long(frame_count), Val_long(frame_time),
