       [0] = new_overall_agitation, [1] = should_store,
       [2..6] = segnum, pos_x, pos_y, pos_z, event_type */
    for (int i = 0; i < 7; i++)
        out_buf[i] = (int32_t)Long_val(Field(result, i));

