    int32_t opx, int32_t opy, int32_t opz,
    int32_t* result)
{
    cd_ox_require_ready("cd_ox_init_controlcen_for_level");
    CAMLparam0();
    CAMLlocal3(v_gp, v_gd, v_result);

    /* Pack gun_points_flat and gun_dirs_flat as OCaml int arrays */
