/* OCaml external: fetch compress objects data as int array */
CAMLprim value cd_ox_effect_fetch_compress_objects_data(value v_unit)
{
    CAMLparam1(v_unit);
    CAMLlocal1(v_result);
    (void)v_unit;

    /* 2 + 2*MAX_OBJECTS = 702 (MAX_OBJECTS=350) */
    int32_t buf[704];
